import React from 'react';
import { Formik, Form } from 'formik';

interface WithFormikProps { onSubmit: any ,initialValues: any ,validationSchema:any ,children: any}


<WithFormik {...WithFormikProps}>
{(formikProps: any) => (
    <div>
      <Field name="mhmad" type="text" label='mhmad' placeholder='placeholder' />
    </div>
)}
</WithFormik>

function WithFormik({initialValues,validationSchema,onSubmit,children,}: WithFormikProps) {
  return (
    <Formik
      initialValues={initialValues}
      validationSchema={validationSchema}
      onSubmit={onSubmit}
    >
      {(formikProps) => (
        <Form>
          {children(formikProps)}

        </Form>
      )}
    </Formik>
  );
}

export default WithFormik;
